function Nav() {
  const [hov, setHov] = useState(null);
  const [scrolled, setScrolled] = useState(false);
  const links = ["About", "Games", "Team", "Socials", "Contact"];

  useEffect(() => {
    const fn = () => setScrolled(window.scrollY > 60);
    window.addEventListener("scroll", fn);
    return () => window.removeEventListener("scroll", fn);
  }, []);

  return (
    <nav className="nav-container" style={{
      position: "fixed", top: 0, left: 0, right: 0, zIndex: 100,
      display: "flex", alignItems: "center", justifyContent: "space-between",
      padding: "2.2rem 4rem",
      background: scrolled ? "rgba(6,6,8,0.97)" : "linear-gradient(to bottom,rgba(6,6,8,0.9),transparent)",
      borderBottom: scrolled ? "1px solid rgba(139,26,26,0.2)" : "none",
      transition: "background 0.4s, border 0.4s",
      backdropFilter: scrolled ? "blur(12px)" : "none",
      fontWeight: "700", // ✅ add this
    }}>
      <a className="nav-brand" href="#hero" style={{
        fontFamily: "var(--font-display)", fontSize: "2.2rem",
        letterSpacing: "0.12em", color: "var(--bone)",
        animation: "flicker 8s ease-in-out infinite",
      }}>
        SILO<span style={{ color: "var(--crimson)" }}>ENTERTAINMENT</span>
      </a>
      <ul className="nav-links" style={{ display: "flex", gap: "2.5rem", listStyle: "none" }}>
        {links.map((l, i) => (
          <li key={i}>
            <a href={l === "Game Jam" ? "/gamejam" : `#${l.toLowerCase()}`}
              onClick={(e) => {
                  if (l === "Game Jam") {
                    e.preventDefault();
                    window.location.href = "https://siloentertainment.in/gamejam";
                  }
              }}

              style={{
                fontFamily: "var(--font-mono)", fontSize: "0.68rem",
                letterSpacing: "0.22em", textTransform: "uppercase",
                color: hov === i ? "var(--crimson)" : "var(--ash)",
                position: "relative", paddingBottom: "4px",
              }}
              onMouseEnter={() => setHov(i)} onMouseLeave={() => setHov(null)}>
              {l}
              <span style={{
                position: "absolute", bottom: 0, left: 0, right: 0, height: 1,
                background: "var(--crimson)",
                transform: hov === i ? "scaleX(1)" : "scaleX(0)",
                transition: "transform 0.3s",
                transformOrigin: "left",
              }} />
            </a>
          </li>
        ))}
      </ul>
    </nav>
  );
}

